import{_ as o,o as t,c as a,a3 as r}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"63. Public Holidays","description":"","frontmatter":{"title":"63. Public Holidays","eba":"Doctors in Training 2022-2026","topics":["leave","public-holidays","preliminary"]},"headers":[],"relativePath":"ebas/doctors-in-training/leave/63-public-holidays.md","filePath":"ebas/doctors-in-training/leave/63-public-holidays.md"}'),i={name:"ebas/doctors-in-training/leave/63-public-holidays.md"};function n(s,e,l,h,d,p){return t(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="_63-public-holidays" tabindex="-1">63. Public Holidays <a class="header-anchor" href="#_63-public-holidays" aria-label="Permalink to &quot;63. Public Holidays&quot;">​</a></h1><p><strong>63.1</strong> Entitlement to be absent on a public holiday</p><p>A Doctor shall be entitled to paid time off (or penalty payments for time worked) in respect of public holidays in accordance with this clause.</p><p><strong>63.2</strong> Public holidays</p><p><strong>(a)</strong> Subject to subclause 63.4 and 63.5, the public holidays to which this clause applies are the days determined under Victorian law as public holidays in respect of the following occasions:</p><p><strong>(i)</strong> New Year’s Day, Australia Day, Christmas Day and Boxing Day; and</p><p><strong>(ii)</strong> Good Friday, the Saturday immediately before Easter Sunday (Easter Saturday), Easter Monday, Anzac Day, Queen’s Birthday and Labour Day; and</p><p><strong>(iii)</strong> Melbourne Cup Day, or in lieu of Melbourne Cup Day, some other day as determined under Victorian law for a particular locality; and</p><p><strong>(iv)</strong> any additional public holiday declared or prescribed in Victoria or a locality in respect of occasions other than those set out in subclause 63.1(a)(i) above.</p><p><strong>(v)</strong> if a day or days are not determined in respect of any of the occasions those set out in subclauses 63.2(a)(i), (ii) or (iii) above under Victorian law in any year, the public holiday for that occasion will be the day or date upon which the public holiday was observed in the previous year.</p><p><strong>63.3</strong> Applicability of penalty payments for some public holidays falling on a weekend</p><p><strong>(a)</strong> When Christmas Day, Australia Day, Boxing Day, or New Year&#39;s Day (Actual Day) is a Saturday or a Sunday, and a substitute or additional holiday is determined under Victorian law on another day in respect of any of those occasions (Other Day):</p><p><strong>(i)</strong> Weekend Workers and casual Doctors shall receive penalty payments pursuant to subclause 63.7 for time worked on the Actual Day or on the Other Day if the Doctor does not work ordinary hours on the Actual Day; and</p><p><strong>(ii)</strong> All other Doctors will receive penalty payments pursuant to subclause</p><p><strong>63.7</strong> for time worked on the Other Day.</p><p><strong>(b)</strong> For the purpose of this clause only, a Weekend Worker is a Doctor who works ordinary hours on a Saturday or Sunday.</p><p><strong>63.4</strong> Substitution of one public holiday for another</p><p><strong>(a)</strong> A Health Service, with the agreement of the Association, may substitute another day for any prescribed in this clause other than Christmas Day, Boxing Day, New Year&#39;s Day and Australia Day as follows:</p><p><strong>(i)</strong> A Health Service and its Doctors may agree to substitute another day for any prescribed in this clause (other than Christmas Day, Boxing Day, New Year&#39;s Day and Australia Day).</p><p><strong>(ii)</strong> An agreement pursuant to subclause 63.4(a)(i) shall be recorded in writing and be available to every affected Doctor.</p><p><strong>(iii)</strong> The Association shall be informed of an agreement pursuant to subclause 63.4(a)(i) and may within seven days refuse to accept it. The Association will not unreasonably refuse to accept the agreement.</p><p><strong>(iv)</strong> If an Association refuses to accept an agreement, the Health Service, the Doctors and the Association will seek to resolve their differences to their mutual satisfaction.</p><p><strong>63.5</strong> Substitution of one public holiday for another</p><p><strong>(a)</strong> Subject to the ongoing operational needs of the Health Service, a Doctor may, with the prior agreement of the Health Service, substitute a public holiday as defined in this clause with a nominated religious holiday that is not a defined public holiday.</p><p><strong>(b)</strong> Where a religious holiday is nominated to be a substitute and the Doctor works on the defined public holiday they will be paid at ordinary time and will be allowed time off on the nominated religious day without loss of pay. Applications are to be made at least one month in advance of the date on which the nominated religious holiday occurs, and the public holiday being substituted.</p><p><strong>63.6</strong> Entitlement to be absent on a public holiday and reasonable request to work</p><p><strong>(a)</strong> A Doctor is entitled to be absent from his or her employment on a day or part-day that is a public holiday in the place where the Doctor is based for work purposes. However, a Health Service may request a Doctor to work on a public holiday provided the request is reasonable.</p><p><strong>(b)</strong> If a Health Service requests a Doctor to work on a public holiday, the Doctor may refuse the request if:</p><p><strong>(i)</strong> the request is not reasonable; or</p><p><strong>(ii)</strong> the refusal is reasonable.</p><p><strong>(c)</strong> In determining whether a request, or a refusal of a request, to work on a public holiday is reasonable, the following must be taken into account:</p><p><strong>(i)</strong> the nature of the Health Service&#39;s workplace or enterprise (including its operational requirements), and the nature of the work performed by the Doctor;</p><p><strong>(ii)</strong> the Doctor’s personal circumstances, including family responsibilities;</p><p><strong>(iii)</strong> whether the Doctor could reasonably expect that the Health Service might request work on the public holiday;</p><p><strong>(iv)</strong> whether the Doctor is entitled to receive overtime payments, penalty rates or other compensation for, or a level of remuneration that reflects an expectation of, work on the public holiday;</p><p><strong>(v)</strong> the type of employment of the Doctor (for example, whether full-time,</p><p><strong>(vi)</strong> the amount of notice in advance of the public holiday given by the Health Service when making the request;</p><p><strong>(vii)</strong> in relation to the refusal of a request – the amount of notice in advance of the public holiday given by the Doctor when refusing the request; and</p><p><strong>(viii)</strong> any other relevant matter.</p><p><strong>(d)</strong> If a Doctor is absent from his or her employment on a day or part-day that is a public holiday where the Doctor has ordinary hours of work on that day, the Health Service must pay the Doctor at the Doctor’s base rate of pay for the Doctor’s ordinary hours of work on the day or part-day.</p><p><strong>63.7</strong> Penalty Payments in Respect of Public Holidays</p><p><strong>(a)</strong> A Doctor who is requested to and does work on a day or part-day that is a Public holiday (or where Christmas Day, Boxing Day, New Year’s Day or Australia Day fall on a weekend, the day to which penalty rates apply pursuant to subclause 63.3) is entitled to be paid for the time worked:</p><p><strong>(i)</strong> at the rate of 250%; or</p><p><strong>(ii)</strong> by mutual agreement, at single time and have 1.5 days added to their annual leave.</p><p><strong>63.8</strong> Public Holidays occurring on rostered days off or day off</p><p><strong>(a)</strong> Subject to subclause 63.8(b), a full-time Doctor will receive a sum equal to one day’s ordinary pay for public holidays that occur on their rostered day off or other day off.</p><p><strong>(b)</strong> Where on each occasion an Other Day (as defined) applies as a public holiday in respect of that occasion, and:</p><p><strong>(i)</strong> the Doctor is rostered off for both the Actual Day and the Other Day (as defined), then only one day’s payment will be made under subclause 63.8(a); or</p><p><strong>(ii)</strong> the Doctor works only on one of either the Actual Day or the Other Day (as defined), and receives penalty rates for the day worked, the Doctor will not receive a payment under subclause 63.8(a) in respect of the day not worked.</p><p><strong>63.9</strong> Public holidays and part-time Doctors</p><p><strong>(a)</strong> Subject to clause 63.9(b), a regular part-time Doctor who is not ordinarily required to work on the day on which a public holiday is observed will not be entitled to payment for such public holiday unless they are required to work on that day.</p><p><strong>(b)</strong> In determining whether a part-time Doctor who works a rotating roster is entitled to receive the &#39;rostered off’ Agreement benefits for a particular public holiday not worked, the Employer will review the roster pattern of the Doctor over the preceding six months. If the rosters show that the Doctor has worked 50% or more of the days on which a particular public holiday falls, the Doctor will be entitled to receive an amount equal to the Doctor’s ordinary rate of pay for the hours the Doctor would normally have worked on that day.</p><p><strong>63.10</strong> Recall on a public holiday</p><p>A benefit arising from subclauses 63.8 or 63.9 will not be diminished where a Doctor is required to, and does, perform recall work on that day.</p><p><strong>63.11</strong> Annual leave on a public holiday</p><p>See <a href="/eba/ebas/doctors-in-training/leave/60-annual-leave.html">clause 60</a> (Annual Leave).</p><p><strong>63.12</strong> Personal leave on a public holiday</p><p>See <a href="/eba/ebas/doctors-in-training/leave/61-personal-sick-carer-s-leave.html">clause 61</a> (Personal/Carer’s Leave).</p><p>Plain language terms: public holiday pay.</p>',59)])])}const y=o(i,[["render",n]]);export{u as __pageData,y as default};
